const PI: f32 = 3.141592653589793;

pub fn fast_sin(x: f32) -> f32 {
    let x = fmodf(x, PI * 2.0);
    let x = if x < 0.0 { x + PI * 2.0 } else { x };
    let i = (x * (256.0 / (2.0 * PI))) as usize;
    SIN_LUT[i.clamp(0, 255)]
}

pub fn fast_cos(x: f32) -> f32 {
    fast_sin(x + PI * 0.5)
}


impl Vec3 {
    pub fn new(x: f32, y: f32, z: f32) -> Self {
        Self { x, y, z }
    }

    pub fn zero() -> Self {
        Self { x: 0.0, y: 0.0, z: 0.0 }
    }

    pub fn rotate_x(self, r: f32) -> Self {
        Self {
            x: self.x,
            y: self.y * fast_cos(r) - self.z * fast_sin(r),
            z: self.y * fast_sin(r) + self.z * fast_cos(r),
        }
    }

    pub fn rotate_y(self, r: f32) -> Self {
        Self {
            x: self.x * fast_cos(r) - self.z * fast_sin(r),
            y: self.y,
            z: self.x * fast_sin(r) + self.z * fast_cos(r),
        }
    }

    pub fn rotate_z(self, r: f32) -> Self {
        Self {
            x: self.x * fast_cos(r) - self.y * fast_sin(r),
            y: self.x * fast_sin(r) + self.y * fast_cos(r),
            z: self.z,
        }
    }

    pub fn max(self, other: Self) -> Self {
        Self {
            x: self.x.max(other.x),
            y: self.x.max(other.y),
            z: self.x.max(other.z),
        }
    }

    pub fn min(self, other: Self) -> Self {
        Self {
            x: self.x.min(other.x),
            y: self.x.min(other.y),
            z: self.x.min(other.z),
        }
    }

    pub fn len(self) -> f32 {
        sqrtf(self.x * self.x + self.y * self.y + self.z * self.z)
    }

    pub fn hsv_to_rgb(self) -> Vec3 {
        let (h, s, v) = (self.x, self.y, self.z);
        let h_ = if h > 1.0 || h < 0.0 { h - floorf(h) } else { h };

        let c = v * s;
        let x = c * (1.0 - (((h_ * 6.0) % 2.0) - 1.0).abs());
        let m = v - c;

        let h6 = h_ * 6.0;

        let (r, g, b) = if h6 < 1.0 {
            (c, x, 0.0)
        } else if h6 < 2.0 {
            (x, c, 0.0)
        } else if h6 < 3.0 {
            (0.0, c, x)
        } else if h6 < 4.0 {
            (0.0, x, c)
        } else if h6 < 5.0 {
            (x, 0.0, c)
        } else {
            (c, 0.0, x)
        };

        Vec3::new(r + m, g + m, b + m)
    }

    pub fn to_rgb8(self) -> RGB8 {
        RGB8::new(
            ((255.0 * self.x) as u8).clamp(0, 0xff),
            ((255.0 * self.y) as u8).clamp(0, 0xff),
            ((255.0 * self.z) as u8).clamp(0, 0xff),
        )
    }
}
